/* monitor.c — COR24 resident monitor
 * UART driver, service vector table, program invocation, shell, and boot init.
 */

int *IO_UARTDATA;
int *IO_UARTSTAT;

/* --- Program invocation globals (used by asm trampoline) --- */

int mon_saved_sp;
int mon_last_rc;

/* --- Program registry (parallel arrays, no structs) --- */

int prog_names[16];
int prog_entries[16];
int prog_flags[16];
int prog_count;

/* --- Shared memory for sws integration --- */

char mon_run_request[32];
int mon_sws_entry;

void uart_init() {
    IO_UARTDATA = 0xFF0100;
    IO_UARTSTAT = 0xFF0101;
}

void uart_putchar(int ch) {
    int stat;
    stat = *IO_UARTSTAT;
    while (stat & 128) {
        stat = *IO_UARTSTAT;
    }
    *IO_UARTDATA = ch;
}

int uart_getchar() {
    int stat;
    stat = *IO_UARTSTAT;
    while (!(stat & 1)) {
        stat = *IO_UARTSTAT;
    }
    return *IO_UARTDATA;
}

void uart_puts(char *s) {
    while (*s) {
        uart_putchar(*s);
        s = s + 1;
    }
}

void uart_put_int(int n) {
    int d;
    int started;
    int div;
    if (n < 0) {
        uart_putchar(45);
        n = 0 - n;
    }
    if (n == 0) {
        uart_putchar(48);
        return;
    }
    div = 100000;
    started = 0;
    while (div > 0) {
        d = n / div;
        if (d > 0 || started) {
            uart_putchar(48 + d);
            started = 1;
        }
        n = n - d * div;
        div = div / 10;
    }
}

/* --- Service vector table --- */

int (*svc_vector[5])();

int svc_putchar(int ch) {
    uart_putchar(ch);
    return 0;
}

int svc_getchar() {
    return uart_getchar();
}

int svc_write(char *buf, int len) {
    int i;
    i = 0;
    while (i < len) {
        uart_putchar(buf[i]);
        i = i + 1;
    }
    return len;
}

int svc_readline(char *buf, int max) {
    int ch;
    int i;
    int done;
    i = 0;
    done = 0;
    while (i < max - 1 && !done) {
        ch = uart_getchar();
        if (ch == 10 || ch == 13) {
            uart_putchar(10);
            done = 1;
        } else if (ch == 8 || ch == 127) {
            if (i > 0) {
                i = i - 1;
                uart_putchar(8);
                uart_putchar(32);
                uart_putchar(8);
            }
        } else {
            buf[i] = ch;
            uart_putchar(ch);
            i = i + 1;
        }
    }
    buf[i] = 0;
    return i;
}

int svc_exit(int rc) {
    /* Placeholder — overwritten by svc_set_exit() with asm impl.
     * If somehow called before wiring, halt. */
    uart_puts("svc_exit: not wired\n");
    while (1) {}
    return rc;
}

void svc_init() {
    svc_vector[0] = svc_putchar;
    svc_vector[1] = svc_getchar;
    svc_vector[2] = svc_write;
    svc_vector[3] = svc_readline;
    svc_vector[4] = svc_exit;
    /* svc_set_exit() overwrites slot 4 with asm svc_exit_impl */
    svc_set_exit();
}

/* --- String helpers --- */

